using System.Collections.Generic;
using UnityEngine;
using UnityEngine.Events;

/// <summary>
/// Configuração de um nível de evolução da vila.
/// </summary>
[System.Serializable]
public class VillageLevelConfig
{
    [Tooltip("Nome do nível para organização no Inspector (ex: 'Nível 0 — Vila Vazia').")]
    public string label = "Nível";

    [Header("Objectos Activos Neste Nível")]
    [Tooltip("GameObjects a activar quando a vila atinge este nível (e a desactivar nos outros).")]
    public List<GameObject> activeObjects = new List<GameObject>();

    [Tooltip("GameObjects a desactivar quando a vila atinge este nível.")]
    public List<GameObject> inactiveObjects = new List<GameObject>();

    [Header("Evento")]
    [Tooltip("Chamado quando a vila entra neste nível.")]
    public UnityEvent onLevelEntered;
}

/// <summary>
/// Controlador de evolução visual de uma vila. Reage automaticamente a
/// <see cref="WorldState.VillagePopulationChanged"/> para actualizar GameObjects,
/// música e outros elementos conforme o nível de restauração calculado por
/// <see cref="WorldState.GetVillageRestorationLevel"/>.
///
/// Configuração no Inspector:
///   • "villageId" — deve corresponder a WorldData.mainVillageId.
///   • "levels" — array de 5 entradas (níveis 0-4); cada entrada define os
///     GameObjects activos/inactivos e um UnityEvent para esse nível.
///   • "firstRescueThreshold" — mínimo de NPCs resgatados para o nível 1 (padrão 2).
///   • "worldForBossCheck" — mundo cujo boss é verificado para o nível 4
///     (deixar vazio se não houver boss para este mundo).
///
/// Montar num GameObject da cena da vila, fora de qualquer NPC.
/// </summary>
public class VillageEvolutionController : MonoBehaviour
{
    [Header("Identificação")]
    [Tooltip("ID da vila (WorldData.mainVillageId) que este controlador monitoriza.")]
    [SerializeField] private string villageId;

    [Header("Configuração de Níveis (0 = Vazia, 1 = Primeiros, 2 = Viva, 3 = Restaurada, 4 = Pós-Boss)")]
    [SerializeField] private List<VillageLevelConfig> levels = new List<VillageLevelConfig>();

    [Header("Regras")]
    [Tooltip("Mínimo de NPCs resgatados para entrar no Nível 1 (padrão 2).")]
    [SerializeField] private int firstRescueThreshold = 2;

    [Tooltip("Mundo cujo boss é verificado para o Nível 4. Deixar vazio se não houver boss.")]
    [SerializeField] private WorldData worldForBossCheck;

    private int _currentLevel = -1;

    // ────────────────────────────────────────────────────────────────────────

    private void OnEnable()
    {
        WorldState.VillagePopulationChanged += OnPopulationChanged;
        ApplyCurrentLevel();
    }

    private void OnDisable()
    {
        WorldState.VillagePopulationChanged -= OnPopulationChanged;
    }

    // ────────────────────────────────────────────────────────────────────────

    private void OnPopulationChanged(string changedVillageId, int current, int max)
    {
        if (changedVillageId != villageId) return;
        ApplyCurrentLevel();
    }

    /// <summary>
    /// Calcula o nível actual e aplica as configurações desse nível.
    /// Pode ser chamado externamente (ex: após carregar um save) para forçar
    /// uma actualização imediata.
    /// </summary>
    public void ApplyCurrentLevel()
    {
        if (string.IsNullOrEmpty(villageId)) return;

        var ws = WorldState.Instance;
        if (ws == null) return;

        bool bossDefeated = worldForBossCheck != null
            && PlayerProgress.Instance != null
            && PlayerProgress.Instance.HasDefeatedBoss(worldForBossCheck);

        int newLevel = ws.GetVillageRestorationLevel(villageId, bossDefeated, firstRescueThreshold);

        // Só aplicar se o nível mudou (evita reconstruir a cena desnecessariamente).
        if (newLevel == _currentLevel) return;

        _currentLevel = newLevel;
        ApplyLevel(newLevel);
    }

    private void ApplyLevel(int level)
    {
        for (int i = 0; i < levels.Count; i++)
        {
            var config = levels[i];
            if (config == null) continue;

            bool isActive = (i == level);

            foreach (var go in config.activeObjects)
                if (go != null) go.SetActive(isActive);

            foreach (var go in config.inactiveObjects)
                if (go != null) go.SetActive(!isActive);

            if (isActive)
                config.onLevelEntered?.Invoke();
        }
    }

    // ────────────────────────────────────────────────────────────────────────

#if UNITY_EDITOR
    private void OnValidate()
    {
        // Garantir que o array tem sempre 5 entradas (níveis 0-4).
        while (levels.Count < 5)
            levels.Add(new VillageLevelConfig { label = $"Nível {levels.Count}" });
    }
#endif
}
